{"code": "import json
import re

# Load clinic data from file
with open('var_functions.query_db_26', 'r') as f:
    brca_patients_full = json.load(f)

# Process clinic data
tcga_to_histology = {}
histology_counts = {}

for patient in brca_patients_full:
    desc = patient["Patient_description"]
    hist_type = patient["histological_type"]

    if hist_type and hist_type != "" and "Other" not in hist_type:
        match = re.search(r'TCGA-[A-Z0-9]+-[A-Z0-9]+', desc)
        if match:
            tcga_id = match.group()
            tcga_to_histology[tcga_id] = hist_type
            histology_counts[hist_type] = histology_counts.get(hist_type, 0) + 1

print("__RESULT__:")
print(json.dumps({
    "unique_patients": len(tcga_to_histology),
    "histology_counts": histology_counts,
    "sample_data": {k: v for k, v in list(tcga_to_histology.items())[:5]}
}))"}

